const axios = require('axios');
const cheerio = require('cheerio');

/**
 * Fetch URL Metadata - Extracts Open Graph tags, title, and description
 * 
 * @param {string} url - URL to fetch metadata from
 * @returns {Object|null} OpenGraph tags or null if an error occurs
 */
exports.fetchUrlMetadata = async (url) => {
   try {
     const { data } = await axios.get(url);
     const $ = cheerio.load(data);

     const result = {
       ogTitle: $('meta[property="og:title"]').attr('content'),
       ogImage: $('meta[property="og:image"]').attr('content'),
       ogDescription: $('meta[property="og:description"]').attr('content'),
       description: $('meta[name="description"]').attr('content'),
       title: $('title').text(),
     };

     if (!Object.values(result).every(value => value)) {
       return null;
     }

     return result;
   } catch (error) {
     console.error(`Error fetching metadata from ${url}: ${error.message}`);
     return null;
   }
};